using System.Collections;
using UnityEngine;

/// <summary>
/// Tarefa #29 — feedback audiovisual de combate do player: pisca do sprite,
/// SFX, vibração do comando, screen shake e VFX (pooled — VfxPoolManager) ao
/// tomar dano, acertar um golpe e morrer.
///
/// Liga-se a:
/// - <see cref="PlayerCombat.OnPlayerDamaged"/> (tomar dano que passou pelos
///   i-frames): pisca o sprite (mesma lógica de EnemyHealth.FlashRoutine),
///   som de dano, screen shake (CameraManager.ShakeHit), vibração e VFX de
///   impacto na posição do player.
/// - <see cref="PlayerAttack.OnHitLanded"/> (golpe acertou pelo menos um
///   alvo): VFX/SFX de impacto no ponto do golpe + vibração leve.
/// - PlayerProgress.OnHeartsDepleted (morte): som/VFX de morte + shake e
///   vibração mais fortes.
/// </summary>
[RequireComponent(typeof(PlayerCombat))]
public class PlayerFeedback : MonoBehaviour
{
    [Header("Tomar Dano")]
    [Tooltip("Som ao tomar dano (e sobreviver).")]
    public AudioClip hurtSound;

    [Tooltip("VFX (pooled — VfxPoolManager) instanciado na posição do player ao tomar dano.")]
    public GameObject hitVfxPrefab;

    [Tooltip("Cor usada no pisca do sprite, alternada com a cor original (mesma ideia de EnemyHealth.flashColor).")]
    public Color flashColor = new Color(1f, 0.4f, 0.4f, 1f);

    [Tooltip("Duração de cada alternância do pisca, em segundos.")]
    public float flashInterval = 0.06f;

    [Tooltip("Duração total do pisca, em segundos.")]
    public float flashDuration = 0.4f;

    [Header("Vibração — Tomar Dano")]
    [Range(0f, 1f)] public float hitRumbleLow = 0.4f;
    [Range(0f, 1f)] public float hitRumbleHigh = 0.7f;
    public float hitRumbleDuration = 0.15f;

    [Header("Acertar um Golpe")]
    [Tooltip("VFX (pooled — VfxPoolManager) instanciado no ponto de impacto ao acertar um golpe (PlayerAttack.OnHitLanded).")]
    public GameObject attackHitVfxPrefab;

    [Tooltip("Som ao acertar um golpe.")]
    public AudioClip attackHitSound;

    [Header("Vibração — Acertar um Golpe")]
    [Range(0f, 1f)] public float attackRumbleLow = 0.15f;
    [Range(0f, 1f)] public float attackRumbleHigh = 0.25f;
    public float attackRumbleDuration = 0.08f;

    [Header("Morte")]
    public AudioClip deathSound;
    public GameObject deathVfxPrefab;

    [Header("Screen Shake — Morte")]
    public float deathShakeAmplitude = 2.5f;
    public float deathShakeFrequency = 2.5f;
    public float deathShakeDuration = 0.35f;

    [Header("Vibração — Morte")]
    [Range(0f, 1f)] public float deathRumbleLow = 0.6f;
    [Range(0f, 1f)] public float deathRumbleHigh = 1f;
    public float deathRumbleDuration = 0.4f;

    private PlayerCombat _combat;
    private PlayerAttack _attack;
    private SpriteRenderer _sprite;
    private Color _baseColor;
    private Coroutine _flashRoutine;

    private void Awake()
    {
        _combat = GetComponent<PlayerCombat>();
        _attack = GetComponent<PlayerAttack>();
        _sprite = GetComponentInChildren<SpriteRenderer>();
        if (_sprite != null) _baseColor = _sprite.color;
    }

    private void OnEnable()
    {
        _combat.OnPlayerDamaged += HandleDamaged;
        if (_attack != null) _attack.OnHitLanded += HandleHitLanded;
        if (PlayerProgress.Instance != null) PlayerProgress.Instance.OnHeartsDepleted += HandleDeath;
    }

    private void OnDisable()
    {
        _combat.OnPlayerDamaged -= HandleDamaged;
        if (_attack != null) _attack.OnHitLanded -= HandleHitLanded;
        if (PlayerProgress.Instance != null) PlayerProgress.Instance.OnHeartsDepleted -= HandleDeath;

        if (_flashRoutine != null) StopCoroutine(_flashRoutine);
        if (_sprite != null) _sprite.color = _baseColor;
    }

    // ==================== PlayerCombat.OnPlayerDamaged ====================

    private void HandleDamaged(DamageInfo info, int finalAmount)
    {
        StartFlash();
        PlaySound(hurtSound, transform.position);
        CameraManager.Instance?.ShakeHit();
        RumbleManager.Instance?.Pulse(hitRumbleLow, hitRumbleHigh, hitRumbleDuration);
        SpawnVfx(hitVfxPrefab, transform.position);
    }

    // ==================== PlayerAttack.OnHitLanded ====================

    private void HandleHitLanded(Vector2 hitPoint)
    {
        SpawnVfx(attackHitVfxPrefab, hitPoint);
        PlaySound(attackHitSound, hitPoint);
        RumbleManager.Instance?.Pulse(attackRumbleLow, attackRumbleHigh, attackRumbleDuration);
    }

    // ==================== PlayerProgress.OnHeartsDepleted ====================

    private void HandleDeath()
    {
        PlaySound(deathSound, transform.position);
        SpawnVfx(deathVfxPrefab, transform.position);
        CameraManager.Instance?.Shake(deathShakeAmplitude, deathShakeFrequency, deathShakeDuration);
        RumbleManager.Instance?.Pulse(deathRumbleLow, deathRumbleHigh, deathRumbleDuration);
    }

    // ==================== Helpers ====================

    private void StartFlash()
    {
        if (_sprite == null) return;
        if (_flashRoutine != null) StopCoroutine(_flashRoutine);
        _flashRoutine = StartCoroutine(FlashRoutine());
    }

    private IEnumerator FlashRoutine()
    {
        // Tarefa #40 — acessibilidade: se "Flashes Reduzidos" estiver activo,
        // faz apenas UMA piscada curta em vez do ciclo completo.
        bool reduced = GameSettings.Instance != null && GameSettings.Instance.ReducedFlashes;

        if (reduced)
        {
            _sprite.color = flashColor;
            yield return new WaitForSeconds(flashInterval);
            _sprite.color = _baseColor;
            _flashRoutine = null;
            yield break;
        }

        float elapsed = 0f;
        bool toggled = false;

        while (elapsed < flashDuration)
        {
            toggled = !toggled;
            _sprite.color = toggled ? flashColor : _baseColor;

            yield return new WaitForSeconds(flashInterval);
            elapsed += flashInterval;
        }

        _sprite.color = _baseColor;
        _flashRoutine = null;
    }

    private void PlaySound(AudioClip clip, Vector3 position)
    {
        if (clip == null) return;
        if (AudioManager.Instance != null) AudioManager.Instance.PlaySEAtPoint(clip, position);
        else AudioSource.PlayClipAtPoint(clip, position);
    }

    private void SpawnVfx(GameObject prefab, Vector3 position)
    {
        if (prefab == null) return;
        if (VfxPoolManager.Instance != null) VfxPoolManager.Instance.Spawn(prefab, position);
        else Instantiate(prefab, position, Quaternion.identity);
    }
}
